export const runtime = "nodejs";

import { NextResponse } from "next/server";
import { sendMail } from "@/lib/mailer";
import fs from "fs/promises";
import path from "path";
import { Client } from "pg";

function ensureAdmin(req: Request) {
  const role = req.headers.get("x-role");
  if (role !== "admin") throw new Error("No autorizado");
}

async function upsertReporte(dateISO: string, filePath: string) {
  const client = new Client({
    connectionString: process.env.DATABASE_URL,
    ssl: process.env.DB_SSL === "true" || /ssl=true/i.test(process.env.DATABASE_URL || "")
      ? { rejectUnauthorized: false }
      : undefined,
  });

  await client.connect();
  try {
    await client.query(
      `
      INSERT INTO reportes(date, file_path)
      VALUES ($1::date, $2)
      ON CONFLICT (date)
      DO UPDATE SET file_path = EXCLUDED.file_path
      `,
      [dateISO, filePath]
    );
  } finally {
    await client.end();
  }
}

export async function POST(req: Request) {
  try {
    ensureAdmin(req);

    const { searchParams } = new URL(req.url);
    const date = searchParams.get("date"); // YYYY-MM-DD
    if (!date) throw new Error("Falta date");

    // 1) Generar Excel (Buffer real)
    const fileName = `reporte_clientes_${date}.xlsx`;
    const excelBuffer = await generarExcelBuffer(date);

    // 2) Guardar archivo en /public/reports  -> accesible en /reports/...
    const reportsDir = path.join(process.cwd(), "public", "reports");
    await fs.mkdir(reportsDir, { recursive: true });

    const diskPath = path.join(reportsDir, fileName);
    await fs.writeFile(diskPath, excelBuffer);

    const publicPath = `/reports/${fileName}`; // esto es lo que usas en el front

    // 3) Guardar (o actualizar) en DB para que salga en la lista
    await upsertReporte(date, publicPath);

    // 4) Enviar email
    const to = process.env.ALAN_EMAIL; // tu config actual
    if (!to) throw new Error("ALAN_EMAIL no configurado");

    await sendMail({
      to,
      subject: `Reporte diario - ${date}`,
      text: `Adjunto el reporte del día ${date}. También quedó guardado en ${publicPath}`,
      attachments: [
        {
          filename: fileName,
          content: excelBuffer,
          contentType:
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        },
      ],
    });

    return NextResponse.json({
      ok: true,
      fileName,
      url: publicPath,
      emailedTo: to,
    });
  } catch (e: any) {
    return NextResponse.json(
      { ok: false, error: e?.message || "Error" },
      { status: 400 }
    );
  }
}

// Reemplaza por tu generación real (exceljs/xlsx)
async function generarExcelBuffer(date: string): Promise<Buffer> {
  const content = `Reporte ${date}`;
  return Buffer.from(content);
}
